cd /Users/markcosciello/git/apple_assessment/weather_project && sqlite3 -header -column data/weather.db "select d.observation_date, s.filename, d.temp_max_f, d.temp_min_f, d.temp_avg_f, d.precip_inches, d.hdd, d.cdd, d.snow_depth, d.daily_temp_max_norm, d.daily_temp_max_record_high, d.daily_temp_max_record_high_year, d.daily_temp_max_record_low, d.daily_temp_max_record_low_year, d.daily_temp_min_norm, d.daily_temp_min_record_high, d.daily_temp_min_record_high_year, d.daily_temp_min_record_low, d.daily_temp_min_record_low_year, d.daily_temp_avg_norm, d.daily_temp_avg_record_high, d.daily_temp_avg_record_high_year, d.daily_temp_avg_record_low, d.daily_temp_avg_record_low_year, d.daily_precip_inches_norm, d.daily_precip_inches_record_high, d.daily_precip_inches_record_high_year, d.daily_precip_inches_record_low, d.daily_precip_inches_record_low_year, d.daily_hdd_norm, d.daily_hdd_record_high, d.daily_hdd_record_high_year, d.daily_hdd_record_low, d.daily_hdd_record_low_year, d.daily_cdd_norm, d.daily_cdd_record_high, d.daily_cdd_record_high_year, d.daily_cdd_record_low, d.daily_cdd_record_low_year from daily_weather d join sources s on s.id=d.source_id where s.kind='pdf' order by d.observation_date;"

